import { create } from 'zustand';

interface FilterState {
    searchWord: string | undefined;
    styleTags: Array<string>;
    alterTags: Array<string>;
    getTags: Array<string>;
    manifestTags: Array<string>;
    typeTags: Array<string>;
    essenTialPersonalityTags: Array<string>;
    choosePersonalityTags: Array<string>;
    invenTags: Array<string>;
    setSearch: (word: string) => void;
    removeTag: (tag: string, essential: boolean) => void;
    addTag: (tag: string, essential: boolean) => void;
    removeFilter: () => void;
}

const initialState = {
    searchWord: undefined,
    styleTags: [
        "style.another",
        "style.extra",
        "style.four",
        "style.normal",
    ],
    alterTags: [
        "alter.false",
        "alter.true",
    ],
    getTags: [
        "get.free",
        "get.notfree",
    ],
    manifestTags: [
        "manifest.step0",
        "manifest.step1",
        "manifest.step2",
    ],
    typeTags: [
        "type.light",
        "type.shadow",
    ],
    essenTialPersonalityTags: [],
    choosePersonalityTags: [],
    invenTags: [
        "inven.nothave",
        "inven.classchange",
        "inven.have",
    ],
}

const useFilterStore = create<FilterState>(
    (set, get) => ({
        ...initialState,
        setSearch: (word) => set((state) => ({
            ...state,
            searchWord: word
        })),
        addTag: (tag, essential = false) => {
            const category = tag.split(".")[0];
            let newState: FilterState | Partial<FilterState>;
            switch (category) {
                case "style":
                    newState = { styleTags: [...get().styleTags, tag] };
                    break
                case "alter":
                    newState = { alterTags: [...get().alterTags, tag] };
                    break
                case "get":
                    newState = { getTags: [...get().getTags, tag] };
                    break
                case "manifest":
                    newState = { manifestTags: [...get().manifestTags, tag] };
                    break
                case "type":
                    newState = { typeTags: [...get().typeTags, tag] };
                    break
                case "inven":
                    newState = { invenTags: [...get().invenTags, tag] };
                    break
                case "personality":
                    if (essential) {
                        newState = { essenTialPersonalityTags: [...get().essenTialPersonalityTags, tag] };
                    } else {
                        newState = { choosePersonalityTags: [...get().choosePersonalityTags, tag] };
                    }
                    break
                default:
                    return
            }
            set((state) => ({
                ...state,
                ...newState
            }))
        },
        removeTag: (tag, essential = false) => {
            const category = tag.split(".")[0];
            let newState: FilterState | Partial<FilterState>;
            switch (category) {
                case "style":
                    newState = { styleTags: get().styleTags.filter((t) => t !== tag) };
                    break
                case "alter":
                    newState = { alterTags: get().alterTags.filter((t) => t !== tag) };
                    break
                case "get":
                    newState = { getTags: get().getTags.filter((t) => t !== tag) };
                    break
                case "manifest":
                    newState = { manifestTags: get().manifestTags.filter((t) => t !== tag) };
                    break
                case "type":
                    newState = { typeTags: get().typeTags.filter((t) => t !== tag) };
                    break
                case "inven":
                    newState = { invenTags: get().invenTags.filter((t) => t !== tag) };
                    break
                case "personality":
                    if (essential) {
                        newState = { essenTialPersonalityTags: get().essenTialPersonalityTags.filter((t) => t !== tag) };
                    } else {
                        newState = { choosePersonalityTags: get().choosePersonalityTags.filter((t) => t !== tag) };
                    }
                    break
                default:
                    return
            }
            set((state) => ({
                ...state,
                ...newState
            }))
        },
        removeFilter: () => {
            set((state) => ({
                ...state,
                ...initialState
            }), true)
        }
    })
);

export default useFilterStore;